from pydantic import BaseModel
from a2a.types import (
    AgentCapabilities,
    AgentCard,
    AgentSkill,
)


class CodeScore(BaseModel):
    recall: float
    precision: float
    f1: float


class CodeEval(BaseModel):
    participants: dict[str, CodeScore]
    winner: str


def judge_agent_card(agent_name: str, card_url: str) -> AgentCard:
    skill = AgentSkill(
        id='judge_code_generation',
        name='Judges generated code',
        description=(
            "Evaluates code generated by multiple agents within a benchmark framework."
            "Given a set of participants and a round configuration, this skill analyzes the generated Python code,"
            "extracts referenced API endpoints and normalizes them."
            "It computes evaluation metrics for each agent and compares agent performances."
        ),
        tags=['coding agent', 'code evaluation', 'OpenAPI'],
        examples=["""
{
  "participants": {
    "PurpleAgent_1": "https://purpleagent_1.example.com:443",
    "PurpleAgent_2": "https://purpleagent_2.example.org:8443"
  },
  "config": {
    "num_rounds": 3
  }
}
"""]
    )
    agent_card = AgentCard(
        name=agent_name,
        description=(
            "Evaluates code generated by multiple agents within the SOCBench-D benchmark framework."
            "Given a set of participants and a round configuration, this skill uses SOCBench-SC to"
            "statically analyze the generated Python code, extract referenced API endpoints"
            "and normalize them according to SOCBench conventions."
            "It then computes precision, recall and F1 scores for each agent and produces structured evaluation reports."
        ),
        url=card_url,
        version='1.0.0',
        default_input_modes=['text'],
        default_output_modes=['text'],
        capabilities=AgentCapabilities(streaming=True),
        skills=[skill],
    )
    return agent_card
